import { Request, Response, NextFunction } from 'express';
import { PostModel } from '../models/post.model';
import { HttpError } from '../errors/http-error';

export const create = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { title, body, scheduledFor } = req.body as { title: string; body: string; scheduledFor?: string };
    let status: 'published' | 'scheduled' = 'published';
    let publishedAt: Date | null = new Date();
    let when: Date | null = null;
    if (scheduledFor) {
      when = new Date(scheduledFor);
      if (when.getTime() < Date.now() + 5 * 60 * 1000) throw new HttpError(400, 'TOO_SOON');
      status = 'scheduled'; publishedAt = null;
    }
    const p = await PostModel.create({ authorId: req.user!.id, title, body, status, scheduledFor: when, publishedAt });
    res.json({ post: p });
  } catch (err) { next(err); }
};

export const reschedule = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const when = new Date(req.body.scheduledFor);
    if (when.getTime() < Date.now() + 5 * 60 * 1000) throw new HttpError(400, 'TOO_SOON');
    const updated = await PostModel.findOneAndUpdate({ _id: req.params.id, authorId: req.user!.id, status: 'scheduled' }, { $set: { scheduledFor: when } }, { new: true });
    if (!updated) throw new HttpError(404, 'NOT_FOUND_OR_LATE');
    res.json({ post: updated });
  } catch (err) { next(err); }
};

