import { Request, Response, NextFunction } from 'express';
import { redis } from '../infra/redis';

export const stream = async (req: Request, res: Response, next: NextFunction) => {
  try {
    res.setHeader('Content-Type', 'text/event-stream');
    res.setHeader('Cache-Control', 'no-cache');
    res.setHeader('Connection', 'keep-alive');
    res.flushHeaders();
    const jobId = req.params.jobId;
    const snapshot = await redis.get(`job:progress:${jobId}`);
    if (snapshot) res.write(`event: progress\ndata: ${snapshot}\n\n`);
    const sub = redis.duplicate();
    await sub.connect();
    await sub.subscribe(`job:progress:${jobId}`, (msg) => {
      res.write(`event: progress\ndata: ${msg}\n\n`);
      const parsed = JSON.parse(msg);
      if (parsed.status === 'done' || parsed.status === 'failed') { res.write('event: end\ndata: {}\n\n'); res.end(); sub.unsubscribe(); sub.quit(); }
    });
    req.on('close', () => { sub.unsubscribe().catch(() => {}); sub.quit().catch(() => {}); });
  } catch (err) { next(err); }
};

import { useEffect, useState } from 'react';

export function ProgressBar({ jobId }: { jobId: string }) {
  const [percent, setPercent] = useState(0);
  const [message, setMessage] = useState('');
  const [done, setDone] = useState(false);
  useEffect(() => {
    const es = new EventSource(`/api/jobs/${jobId}/progress`);
    es.addEventListener('progress', (e) => {
      const d = JSON.parse((e as MessageEvent).data) as { percent: number; message: string; status: string };
      setPercent(d.percent); setMessage(d.message);
      if (d.status === 'done' || d.status === 'failed') setDone(true);
    });
    es.addEventListener('end', () => es.close());
    return () => es.close();
  }, [jobId]);
  return (
    <div>
      <div className="w-full h-2 bg-gray-200 rounded"><div className="h-2 bg-blue-500 rounded transition-all" style={{ width: `${percent}%` }} /></div>
      <div className="text-xs text-gray-500 mt-1">{message}{done && ' - Done'}</div>
    </div>
  );
}

