import { Router, Request, Response, NextFunction } from 'express';
import { z, ZodSchema } from 'zod';

type Method = 'get' | 'post' | 'patch' | 'put' | 'delete';

export type RouteDef<P, B, R> = {
  method: Method;
  path: string;
  params?: ZodSchema<P>;
  body?: ZodSchema<B>;
  middlewares?: ((req: Request, res: Response, next: NextFunction) => void)[];
  handler: (ctx: { params: P; body: B; req: Request; res: Response }) => Promise<R>;
};

export function registerRoutes(router: Router, routes: RouteDef<unknown, unknown, unknown>[]) {
  for (const route of routes) {
    router[route.method](route.path, ...(route.middlewares ?? []), async (req, res, next) => {
      try {
        const params = route.params ? route.params.parse(req.params) : (req.params as unknown);
        const body = route.body ? route.body.parse(req.body) : (req.body as unknown);
        const result = await route.handler({ params, body, req, res });
        if (!res.headersSent) res.json(result);
      } catch (err) { next(err); }
    });
  }
}

export function defineRoute<P, B, R>(def: RouteDef<P, B, R>): RouteDef<unknown, unknown, unknown> { return def as unknown as RouteDef<unknown, unknown, unknown>; }

