import { useFrame, useThree } from '@react-three/fiber';
import { useRef, useEffect } from 'react';
import * as THREE from 'three';

export type Waypoint = { pos: [number, number, number]; target: [number, number, number] };

export function CameraRig({ waypoint, durationMs = 1500 }: { waypoint: Waypoint | null; durationMs?: number }) {
  const { camera } = useThree();
  const start = useRef<{ pos: THREE.Vector3; target: THREE.Vector3 } | null>(null);
  const startTime = useRef(0);
  const target = useRef<THREE.Vector3>(new THREE.Vector3(0, 0, 0));

  useEffect(() => {
    if (!waypoint) return;
    start.current = { pos: camera.position.clone(), target: target.current.clone() };
    startTime.current = performance.now();
  }, [waypoint, camera]);

  useFrame(() => {
    if (!waypoint || !start.current) return;
    const elapsed = (performance.now() - startTime.current) / durationMs;
    const t = Math.min(1, elapsed);
    const e = t * t * (3 - 2 * t);
    camera.position.lerpVectors(start.current.pos, new THREE.Vector3(...waypoint.pos), e);
    target.current.lerpVectors(start.current.target, new THREE.Vector3(...waypoint.target), e);
    camera.lookAt(target.current);
  });
  return null;
}

