function patternToRegex(p: string): RegExp {
  const escaped = p.split('.').map(seg => seg === '*' ? '[^.]+' : seg.replace(/[.+?^${}()|[\]\\]/g, '\\$&')).join('\\.');
  return new RegExp(`^${escaped}$`);
}
const cache = new Map<string, RegExp>();
function toRegex(p: string): RegExp {
  let r = cache.get(p);
  if (!r) { r = patternToRegex(p); cache.set(p, r); }
  return r;
}
export function matchesTopics(eventType: string, patterns: string[]): boolean {
  return patterns.some(p => p === '*' || p === eventType || toRegex(p).test(eventType));
}

import { WebhookSubscriptionModel } from '../models/webhook-subscription.model';
import { matchesTopics } from './topic-match';
import { enqueueWebhook } from '../queue/per-tenant-webhook';

export async function fire(orgId: string, eventType: string, payload: unknown) {
  const subs = await WebhookSubscriptionModel.find({ orgId, status: 'active' });
  for (const sub of subs) {
    if (!matchesTopics(eventType, sub.topics)) continue;
    await enqueueWebhook(orgId, { subscriptionId: String(sub._id), eventType, payload });
  }
}

