import * as THREE from 'three';

export class PointCloudChunk {
  mesh: THREE.Points;
  constructor(positions: Float32Array, colors: Uint8Array) {
    const geometry = new THREE.BufferGeometry();
    geometry.setAttribute('position', new THREE.BufferAttribute(positions, 3));
    geometry.setAttribute('color', new THREE.BufferAttribute(colors, 3, true));
    geometry.computeBoundingSphere();
    const material = new THREE.PointsMaterial({ size: 0.02, vertexColors: true });
    this.mesh = new THREE.Points(geometry, material);
  }
  dispose() { this.mesh.geometry.dispose(); (this.mesh.material as THREE.Material).dispose(); }
}

import { Canvas, useThree, useFrame } from '@react-three/fiber';
import { OrbitControls } from '@react-three/drei';
import { Suspense, useEffect, useRef } from 'react';
import * as THREE from 'three';
import { PointCloudChunk } from './PointCloudChunk';

type ChunkMeta = { id: string; bounds: [number, number, number, number, number, number]; lodUrls: string[] };

function Cloud({ chunks }: { chunks: ChunkMeta[] }) {
  const groupRef = useRef<THREE.Group>(null);
  const loaded = useRef(new Map<string, { chunk: PointCloudChunk; lod: number }>());
  const { camera } = useThree();

  useFrame(() => {
    const frustum = new THREE.Frustum();
    frustum.setFromProjectionMatrix(new THREE.Matrix4().multiplyMatrices(camera.projectionMatrix, camera.matrixWorldInverse));
    for (const meta of chunks) {
      const box = new THREE.Box3(new THREE.Vector3(meta.bounds[0], meta.bounds[1], meta.bounds[2]), new THREE.Vector3(meta.bounds[3], meta.bounds[4], meta.bounds[5]));
      const visible = frustum.intersectsBox(box);
      const center = box.getCenter(new THREE.Vector3());
      const dist = camera.position.distanceTo(center);
      const desiredLod = dist > 100 ? 2 : dist > 40 ? 1 : 0;
      const current = loaded.current.get(meta.id);
      if (!visible && current) { groupRef.current?.remove(current.chunk.mesh); current.chunk.dispose(); loaded.current.delete(meta.id); }
      else if (visible && (!current || current.lod !== desiredLod)) {
        if (current) { groupRef.current?.remove(current.chunk.mesh); current.chunk.dispose(); }
        void loadChunk(meta, desiredLod).then(chunk => { loaded.current.set(meta.id, { chunk, lod: desiredLod }); groupRef.current?.add(chunk.mesh); });
      }
    }
  });

  useEffect(() => () => { for (const c of loaded.current.values()) c.chunk.dispose(); loaded.current.clear(); }, []);
  return <group ref={groupRef} />;
}

async function loadChunk(meta: ChunkMeta, lod: number): Promise<PointCloudChunk> {
  const buf = await (await fetch(meta.lodUrls[lod])).arrayBuffer();
  const view = new DataView(buf);
  const pointCount = view.getUint32(0, true);
  const positions = new Float32Array(buf, 4, pointCount * 3);
  const colors = new Uint8Array(buf, 4 + pointCount * 12, pointCount * 3);
  return new PointCloudChunk(positions, colors);
}

export function LidarViewer({ chunks }: { chunks: ChunkMeta[] }) {
  return (
    <div className="w-full h-screen">
      <Canvas camera={{ position: [0, 10, 30], fov: 50 }} dpr={[1, 2]}>
        <Suspense fallback={null}><Cloud chunks={chunks} /></Suspense>
