    </div>
  );
}

import { Server, Socket } from 'socket.io';

type Lobby = { id: string; players: string[]; startsAt: number | null };
const lobbies = new Map<string, Lobby>();

function broadcast(io: Server, lobby: Lobby) {
  io.of('/lobby').to(`lobby:${lobby.id}`).emit('lobby:update', { players: lobby.players, startsAt: lobby.startsAt, serverTime: Date.now() });
}

export function attachLobbyNamespace(io: Server) {
  const ns = io.of('/lobby');
  ns.on('connection', (socket: Socket) => {
    const userId = (socket as any).data.userId as string;
    socket.on('lobby:join', (lobbyId: string) => {
      let lobby = lobbies.get(lobbyId);
      if (!lobby) { lobby = { id: lobbyId, players: [], startsAt: null }; lobbies.set(lobbyId, lobby); }
      if (!lobby.players.includes(userId)) lobby.players.push(userId);
      socket.join(`lobby:${lobbyId}`);
      if (lobby.players.length >= 2 && lobby.startsAt === null) lobby.startsAt = Date.now() + 30_000;
      broadcast(io, lobby);
    });
    socket.on('disconnect', () => {
      for (const lobby of lobbies.values()) {
        const idx = lobby.players.indexOf(userId);
        if (idx >= 0) {
          lobby.players.splice(idx, 1);
          if (lobby.players.length < 2) lobby.startsAt = null;
          broadcast(io, lobby);
        }
      }
    });
  });
}

import { useEffect, useState } from 'react';
import { io } from 'socket.io-client';

export function Lobby({ lobbyId, token }: { lobbyId: string; token: string }) {
  const [players, setPlayers] = useState<string[]>([]);
  const [startsAt, setStartsAt] = useState<number | null>(null);
  const [clockOffset, setClockOffset] = useState(0);
  const [remaining, setRemaining] = useState(0);

  useEffect(() => {
    const socket = io('/lobby', { auth: { token } });
    socket.emit('lobby:join', lobbyId);
    socket.on('lobby:update', (u: { players: string[]; startsAt: number | null; serverTime: number }) => {
      setPlayers(u.players);
      setStartsAt(u.startsAt);
      setClockOffset(u.serverTime - Date.now());
    });
    return () => { socket.disconnect(); };
  }, [lobbyId, token]);

  useEffect(() => {
    const i = setInterval(() => {
      if (startsAt === null) { setRemaining(0); return; }
      const r = Math.max(0, startsAt - (Date.now() + clockOffset));
      setRemaining(r);
    }, 100);
    return () => clearInterval(i);
  }, [startsAt, clockOffset]);

  return (
    <div>
      <div>Players: {players.length}</div>
      {startsAt === null ? <div>Waiting for players...</div> : <div>Starts in {Math.ceil(remaining / 1000)}s</div>}
    </div>
  );
}

