import { Request, Response, NextFunction } from 'express';
import Papa from 'papaparse';
import { z } from 'zod';
import { ContactModel } from '../models/contact.model';
import { HttpError } from '../errors/http-error';

const targetSchema = z.object({ email: z.string().email(), name: z.string().min(1).optional() });

export const preview = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const text = (req.file?.buffer ?? Buffer.alloc(0)).toString('utf8');
    const parsed = Papa.parse<string[]>(text, { skipEmptyLines: true });
    const headers = (parsed.data[0] as string[]) ?? [];
    const rows = (parsed.data.slice(1, 6) as string[][]);
    res.json({ headers, sampleRows: rows, targets: ['email', 'name'], required: ['email'] });
  } catch (err) { next(err); }
};

export const runImport = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { mapping, csvText } = req.body as { mapping: Record<string, string>; csvText: string };
    const required = ['email'];
    for (const t of required) if (!Object.values(mapping).includes(t)) throw new HttpError(400, `MISSING_MAPPING_FOR:${t}`);
    const parsed = Papa.parse<string[]>(csvText, { skipEmptyLines: true });
    const headers = parsed.data[0] as string[];
    const headerIdx = Object.fromEntries(headers.map((h, i) => [h, i]));
    const errors: { row: number; reason: string }[] = [];
    let imported = 0;
    for (let r = 1; r < parsed.data.length; r++) {
      const row = parsed.data[r] as string[];
      const record: Record<string, string> = {};
      for (const [src, dst] of Object.entries(mapping)) record[dst] = row[headerIdx[src]] ?? '';
      const val = targetSchema.safeParse(record);
      if (!val.success) { errors.push({ row: r, reason: val.error.issues.map(i => i.message).join('; ') }); continue; }
      await ContactModel.create({ orgId: (req as any).orgId, ...val.data });
      imported++;
    }
    res.json({ imported, errors });
  } catch (err) { next(err); }
};

import { useState } from 'react';

export function CsvImport() {
  const [preview, setPreview] = useState<{ headers: string[]; sampleRows: string[][]; targets: string[]; required: string[] } | null>(null);
  const [csvText, setCsvText] = useState<string>('');
  const [mapping, setMapping] = useState<Record<string, string>>({});

  const onFile = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]; if (!file) return;
    const text = await file.text();
    setCsvText(text);
    const fd = new FormData(); fd.append('file', file);
    const res = await fetch('/api/imports/csv/preview', { method: 'POST', credentials: 'include', body: fd }).then(r => r.json());
    setPreview(res);
    setMapping({});
  };

  const runImport = async () => {
    const res = await fetch('/api/imports/csv/run', { method: 'POST', credentials: 'include', headers: { 'content-type': 'application/json' }, body: JSON.stringify({ mapping, csvText }) }).then(r => r.json());
    alert(`Imported ${res.imported}, errors ${res.errors.length}`);
  };

  return (
    <div className="space-y-3">
      <input type="file" accept=".csv" onChange={onFile} />
      {preview && (
        <div>
