export const reportService = {
  async sales(orgId: string, from: Date, to: Date) {
    const k = key(orgId, { from: from.toISOString(), to: to.toISOString() });
    const cached = await redis.get(k);
    if (cached) return JSON.parse(cached);
    const result = await OrderModel.aggregate([{ $match: { orgId, createdAt: { $gte: from, $lte: to } } }, { $group: { _id: '$status', n: { $sum: 1 } } }]);
    await redis.set(k, JSON.stringify(result), { EX: TTL_SECONDS });
    return result;
  },
  async invalidate(orgId: string) {
    const cursor = redis.scanIterator({ MATCH: `report:sales:${orgId}:*` });
    for await (const k of cursor) await redis.del(k);
  }
};

