import { useEffect, useReducer, useCallback } from 'react';
import { z, ZodSchema } from 'zod';

type Step<T> = { id: string; schema: ZodSchema<T>; default: T };
type State = { step: number; data: Record<string, unknown>; errors: Record<string, string> };
type Action = { type: 'set'; stepId: string; value: unknown } | { type: 'next' } | { type: 'prev' } | { type: 'jump'; step: number } | { type: 'errors'; e: Record<string, string> } | { type: 'reset'; init: State };

function reducer(state: State, action: Action): State {
  switch (action.type) {
    case 'set': return { ...state, data: { ...state.data, [action.stepId]: action.value }, errors: { ...state.errors, [action.stepId]: '' } };
    case 'next': return { ...state, step: state.step + 1 };
    case 'prev': return { ...state, step: Math.max(0, state.step - 1) };
    case 'jump': return { ...state, step: action.step };
    case 'errors': return { ...state, errors: action.e };
    case 'reset': return action.init;
  }
}

export function useWizard<S extends Step<unknown>[]>(key: string, steps: S) {
  const [state, dispatch] = useReducer(reducer, undefined, () => {
    try { const raw = localStorage.getItem(`wizard:${key}`); if (raw) return JSON.parse(raw); } catch {}
    return { step: 0, data: Object.fromEntries(steps.map(s => [s.id, s.default])), errors: {} };
  });

  useEffect(() => { try { localStorage.setItem(`wizard:${key}`, JSON.stringify(state)); } catch {} }, [key, state]);

  const setValue = useCallback((stepId: string, value: unknown) => dispatch({ type: 'set', stepId, value }), []);
  const next = useCallback(() => {
    const current = steps[state.step];
    if (!current) return;
    const parsed = current.schema.safeParse(state.data[current.id]);
    if (!parsed.success) {
      dispatch({ type: 'errors', e: { ...state.errors, [current.id]: parsed.error.issues.map(i => i.message).join('; ') } });
      return;
    }
    dispatch({ type: 'next' });
  }, [state, steps]);
  const prev = useCallback(() => dispatch({ type: 'prev' }), []);
  const reset = useCallback(() => dispatch({ type: 'reset', init: { step: 0, data: Object.fromEntries(steps.map(s => [s.id, s.default])), errors: {} } }), [steps]);
  return { state, setValue, next, prev, reset };
}

