export const refresh = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const presented = req.cookies?.rt;
    if (!presented) throw new HttpError(401, 'NO_REFRESH');
    const stored = await RefreshTokenModel.findOne({ /* lookup */ });
    const fp = fingerprintFromRequest(req as unknown as { headers: Record<string, string | string[] | undefined> });
    if (stored?.deviceFp && similarity(stored.deviceFp, fp) < 0.85) throw new HttpError(401, 'DEVICE_MISMATCH');
    const pair = await rotateRefresh(presented);
    await RefreshTokenModel.updateOne({ jti: pair.refreshJti }, { $set: { deviceFp: fp } });
    res.cookie('rt', pair.refresh, { httpOnly: true, sameSite: 'lax', secure: true });
    res.json({ token: pair.access });
  } catch (err) { next(err); }
};

