function CameraTo({ pos }: { pos: [number, number, number] }) {
  const { camera } = useThree();
  const target = useRef(new THREE.Vector3(...pos));
  const reduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  useEffect(() => { target.current.set(pos[0], pos[1], pos[2]); }, [pos]);
  useFrame(() => {
    const dest = target.current.clone().add(new THREE.Vector3(2, 1, 4));
    if (reduced) camera.position.copy(dest);
    else camera.position.lerp(dest, 0.1);
    camera.lookAt(target.current);
  });
  return null;
}

export function Viewer() {
