import { QuotaModel } from '../models/quota.model';
import { FileModel } from '../models/file.model';
import { enqueue } from '../queue/enqueue';

export async function recalcQuotas() {
  const orgs = await QuotaModel.find({});
  for (const q of orgs) {
    const agg = await FileModel.aggregate([{ $match: { orgId: q.orgId } }, { $group: { _id: null, total: { $sum: '$size' } } }]);
    const used = agg[0]?.total ?? 0;
    q.storageBytes = used;
    const pct = used / q.storageLimit;
    const prev = q.state;
    if (pct >= 1) {
      if (q.state === 'ok' || q.state === 'warning') { q.state = 'grace'; q.graceUntil = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000); }
      else if (q.state === 'grace' && q.graceUntil && q.graceUntil.getTime() < Date.now()) q.state = 'blocked';
    } else if (pct >= 0.8) {
      if (q.state === 'ok') q.state = 'warning';
    } else q.state = 'ok';
    if (prev !== q.state) await enqueue.email({ to: String(q.orgId), template: 'quota-change', data: { state: q.state, pct: Math.round(pct * 100) } });
    await q.save();
  }
}

import { Request, Response, NextFunction } from 'express';
import { QuotaModel } from '../models/quota.model';
import { HttpError } from '../errors/http-error';

export async function quotaBlock(req: Request, _res: Response, next: NextFunction) {
  const orgId = (req as any).orgId;
  if (!orgId) return next();
  const q = await QuotaModel.findOne({ orgId }).lean();
  if (q?.state === 'blocked') return next(new HttpError(402, 'QUOTA_EXCEEDED'));
  next();
}
